mapper.select:
SELECT id, schedule_id, slot_seq, slot_start, slot_end, status, version, create_time, update_time
FROM slot
WHERE id = #{id}

mapper.update:
UPDATE slot SET status = #{status}, version = version + 1, update_time = NOW()
WHERE id = #{id}
  AND status = 'AVAILABLE'
  AND version = #{version}

UPDATE slot SET status = 'AVAILABLE', version = version + 1, update_time = NOW()
WHERE id = #{id}
  AND status = 'BOOKED'
  AND version = #{version}

UPDATE slot SET status = #{status}, version = version + 1, update_time = NOW()
WHERE schedule_id = #{scheduleId}
  AND status IN ('AVAILABLE', 'BOOKED')
